// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/components", wrapper.ListComponents)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/config/notifications", wrapper.GetNotificationConfig)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/config/notifications", wrapper.UpdateNotificationConfig)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/config/scanners", wrapper.GetScannerConfig)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/config/scanners", wrapper.UpdateScannerConfig)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/cve-watch/findings", wrapper.ListCVEWatchFindings)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/ingestions/{id}", wrapper.GetIngestion)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products", wrapper.ListProducts)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/products", wrapper.CreateProduct)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products/{id}/projects", wrapper.ListProjects)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/products/{id}/projects", wrapper.CreateProject)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products/{id}/versions", wrapper.ListProductVersions)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/projects/{id}/scans", wrapper.ListProjectScans)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/sbom/upload", wrapper.UploadSBOM)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/scans/{id}", wrapper.GetScan)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/scans/{id}/vulnerabilities", wrapper.ListScanVulnerabilities)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/vex/upload", wrapper.UploadVEX)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/vulnerabilities/{id}/triage", wrapper.SubmitTriage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/vulnerabilities/{id}/triage/history", wrapper.GetTriageHistory)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/webhooks/scan", wrapper.WebhookScan)
	})

	return r
}

